#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int L, q;
        scanf("%d %d", &L, &q);
        printf("Case %d:\n", t + 1);
        for (int i = 0; i < L; i++) {
            long long N;
            scanf("%lld", &N);
            long long result = 1;
            for (long long j = 2; j * j <= N; j++) {
                if (N % j == 0) {
                    int count = 0;
                    while (N % j == 0) {
                        N /= j;
                        count++;
                    }
                    result = (result * (j - 1)) % q;
                    for (int k = 1; k < count; k++) {
                        result = (result * j) % q;
                    }
                }
            }
            if (N > 1) {
                result = (result * (N - 1)) % q;
            }
            printf("%lld\n", result);
        }
    }
    return 0;
}

